import React, { useEffect } from "react";
import { PRIORITY_META, STATUS_META } from "../utils/costants";

export default function FeatureModal({ feature, onClose }) {
  useEffect(() => {
    const handler = (e) => {
      if (e.key === "Escape") onClose();
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [onClose]);

  if (!feature) return null;

  const pm = PRIORITY_META[feature.priority];
  const sm = STATUS_META[feature.status];

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 1000,
        background: "rgba(0, 0, 0, 0.5)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: "16px",
      }}
      onClick={(e) => e.target === e.currentTarget && onClose()}
    >
      <div
        style={{
          background: "white",
          borderRadius: "8px",
          boxShadow: "0 10px 40px rgba(0, 0, 0, 0.2)",
          maxWidth: "600px",
          width: "100%",
          maxHeight: "90vh",
          overflow: "auto",
        }}
      >
        {/* Header */}
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            padding: "20px 24px",
            borderBottom: "1px solid #e5e7eb",
          }}
        >
          <h2 style={{ margin: 0, fontSize: "20px", fontWeight: 600 }}>
            Feature Details
          </h2>
          <button
            onClick={onClose}
            style={{
              background: "none",
              border: "none",
              fontSize: "24px",
              cursor: "pointer",
              color: "#6b7280",
              padding: "0",
              width: "32px",
              height: "32px",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
            }}
          >
            ✕
          </button>
        </div>

        {/* Body */}
        <div style={{ padding: "24px" }}>
          {/* Title */}
          <div style={{ marginBottom: "20px" }}>
            <label style={{ fontSize: "12px", fontWeight: 700, color: "#6b7280", display: "block", marginBottom: "6px" }}>
              TITLE
            </label>
            <div
              style={{
                padding: "10px 14px",
                background: "#f9fafb",
                border: "1px solid #e5e7eb",
                borderRadius: "6px",
                fontSize: "14px",
                color: "#1f2937",
              }}
            >
              {feature.title}
            </div>
          </div>

          {/* Description */}
          <div style={{ marginBottom: "20px" }}>
            <label style={{ fontSize: "12px", fontWeight: 700, color: "#6b7280", display: "block", marginBottom: "6px" }}>
              DESCRIPTION
            </label>
            <div
              style={{
                padding: "10px 14px",
                background: "#f9fafb",
                border: "1px solid #e5e7eb",
                borderRadius: "6px",
                fontSize: "13px",
                color: "#374151",
                lineHeight: "1.6",
                whiteSpace: "pre-wrap",
                minHeight: "100px",
              }}
            >
              {feature.description}
            </div>
          </div>

          {/* Priority & Status */}
          <div style={{ display: "flex", gap: "16px", marginBottom: "20px" }}>
            <div style={{ flex: 1 }}>
              <label style={{ fontSize: "12px", fontWeight: 700, color: "#6b7280", display: "block", marginBottom: "6px" }}>
                PRIORITY
              </label>
              <div
                style={{
                  padding: "10px 14px",
                  background: "white",
                  border: `1px solid ${pm?.color || "#e5e7eb"}`,
                  borderRadius: "6px",
                  fontSize: "13px",
                  fontWeight: 600,
                  color: pm?.color || "#6b7280",
                }}
              >
                {feature.priority}
              </div>
            </div>
            <div style={{ flex: 1 }}>
              <label style={{ fontSize: "12px", fontWeight: 700, color: "#6b7280", display: "block", marginBottom: "6px" }}>
                STATUS
              </label>
              <div
                style={{
                  padding: "10px 14px",
                  background: "white",
                  border: `1px solid ${sm?.color || "#e5e7eb"}`,
                  borderRadius: "6px",
                  fontSize: "13px",
                  fontWeight: 600,
                  color: sm?.color || "#6b7280",
                }}
              >
                {sm?.icon} {feature.status}
              </div>
            </div>
          </div>

          {/* Image */}
          {feature.image && (
            <div style={{ marginBottom: "20px" }}>
              <label style={{ fontSize: "12px", fontWeight: 700, color: "#6b7280", display: "block", marginBottom: "6px" }}>
                IMAGE
              </label>
              <img
                src={`http://localhost:5000/api/features/images/${feature.image}`}
                alt={feature.title}
                style={{
                  maxWidth: "100%",
                  maxHeight: "300px",
                  borderRadius: "6px",
                  border: "1px solid #e5e7eb",
                }}
              />
            </div>
          )}

          {/* Close Button */}
          <button
            onClick={onClose}
            style={{
              width: "100%",
              padding: "10px 14px",
              background: "#f3f4f6",
              border: "1px solid #d1d5db",
              borderRadius: "6px",
              fontSize: "14px",
              fontWeight: 600,
              cursor: "pointer",
              color: "#1f2937",
              marginTop: "16px",
            }}
          >
            Close
          </button>
        </div>
      </div>
    </div>
  );
}
